			// 			...a,
			// 			time: dayjs(a.time).add(randomInt, 'hour').toISOString(),
			// 			event: "checkout",
			// 			amount: a.amount * 2,
			// 			coupon: "50%OFF"
			// 		};
			// 		return newCheckout;
			// 	});
			// 	record.push(...newCheckouts);
			// }

			// //users who watch low quality videos churn more:
			// const loQuality = ["480p", "360p", "240p"];
